```razor
@page "/courses"
@rendermode InteractiveServer
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, instructors..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(searchTerm, selectedDepartmentId);
}

<p class="text-muted">Showing @results.Count course(s)</p>

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <div class="row">
        @foreach (var course in results)
        {
            var dept = Catalog.GetDepartment(course.DepartmentId);
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.CourseCode</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text">
                            <span class="badge bg-secondary">@dept?.Name</span>
                            <span class="badge bg-info text-dark">@course.Credits credits</span>
                        </p>
                        <p class="card-text small">@Truncate(course.Description, 120)</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string? searchTerm;
    private int selectedDepartmentId;
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}
```

