@page "/courses"
@rendermode InteractiveServer
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, instructors..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="selectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(searchTerm, selectedDepartmentId);
}

<p class="text-muted">Showing @results.Count course(s)</p>

@if (results.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <div class="row">
        @foreach (var course in results)
        {
            var dept = Catalog.GetDepartment(course.DepartmentId);
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.CourseCode</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text">
                            <span class="badge bg-secondary">@dept?.Name</span>
                            <span class="badge bg-info text-dark">@course.Credits credits</span>
                        </p>
                        <p class="card-text small">@Truncate(course.Description, 120)</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private string? searchTerm;
    private int selectedDepartmentId;
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using Microsoft.AspNetCore.Components.Forms
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    var selectedCourse = Catalog.GetCourse(Model.CourseId);
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong> (ID: @Model.StudentId).</p>
        <p>Your enrollment request for <strong>@selectedCourse?.CourseCode — @selectedCourse?.Title</strong> has been received and will be processed by the registrar.</p>
        <hr />
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <p class="text-muted">Fill out the form below to request enrollment in a course. All fields are required.</p>

    <div class="row">
        <div class="col-lg-6">
            <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                <DataAnnotationsValidator />
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
                    <ValidationMessage For="() => Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

